230: func isObsoleteDev(dev string, devices []string) bool {
231: 	// exclude devices we never attach to/from_netdev to.
232: 	for _, prefix := range defaults.ExcludedDevicePrefixes {
233: 		if strings.HasPrefix(dev, prefix) {
234: 			return false
235: 		}
236: 	}
237: 
238: 	// exclude devices that will still be managed going forward.
239: 	for _, d := range devices {
240: 		if dev == d {
241: 			return false
242: 		}
243: 	}
244: 
245: 	return true
246: }
