248: // removeObsoleteNetdevPrograms removes cil_to_netdev and cil_from_netdev from devices
249: // that cilium potentially doesn't manage anymore after a restart, e.g. if the set of
250: // devices changes between restarts.
251: //
252: // This code assumes that the agent was upgraded from a prior version while maintaining
253: // the same list of managed physical devices. This ensures that all tc bpf filters get
254: // replaced using the naming convention of the 'current' agent build. For example,
255: // before 1.13, most filters were named e.g. bpf_host.o:[to-host], to be changed to
256: // cilium-<device> in 1.13, then to cil_to_host-<device> in 1.14. As a result, this
257: // function only cleans up filters following the current naming scheme.
258: func removeObsoleteNetdevPrograms(devices []string) error {
259: 	links, err := safenetlink.LinkList()
260: 	if err != nil {
261: 		return fmt.Errorf("retrieving all netlink devices: %w", err)
262: 	}
263: 
264: 	// collect all devices that have netdev programs attached on either ingress or egress.
265: 	ingressDevs := []netlink.Link{}
266: 	egressDevs := []netlink.Link{}
267: 	for _, l := range links {
268: 		if !isObsoleteDev(l.Attrs().Name, devices) {
269: 			continue
270: 		}
271: 
272: 		// Remove the per-device bpffs directory containing pinned links and
273: 		// per-endpoint maps.
274: 		bpffsPath := bpffsDeviceDir(bpf.CiliumPath(), l)
275: 		if err := bpf.Remove(bpffsPath); err != nil {
276: 			log.WithError(err).WithField(logfields.Device, l.Attrs().Name)
277: 		}
278: 
279: 		ingressFilters, err := safenetlink.FilterList(l, directionToParent(dirIngress))
280: 		if err != nil {
281: 			return fmt.Errorf("listing ingress filters: %w", err)
282: 		}
283: 		for _, filter := range ingressFilters {
284: 			if bpfFilter, ok := filter.(*netlink.BpfFilter); ok {
285: 				if strings.HasPrefix(bpfFilter.Name, symbolFromHostNetdevEp) {
286: 					ingressDevs = append(ingressDevs, l)
287: 				}
288: 			}
289: 		}
290: 
291: 		egressFilters, err := safenetlink.FilterList(l, directionToParent(dirEgress))
292: 		if err != nil {
293: 			return fmt.Errorf("listing egress filters: %w", err)
294: 		}
295: 		for _, filter := range egressFilters {
296: 			if bpfFilter, ok := filter.(*netlink.BpfFilter); ok {
297: 				if strings.HasPrefix(bpfFilter.Name, symbolToHostNetdevEp) {
298: 					egressDevs = append(egressDevs, l)
299: 				}
300: 			}
301: 		}
302: 	}
303: 
304: 	for _, dev := range ingressDevs {
305: 		err = removeTCFilters(dev, directionToParent(dirIngress))
306: 		if err != nil {
307: 			log.WithError(err).Errorf("couldn't remove ingress tc filters from %s", dev.Attrs().Name)
308: 		}
309: 	}
310: 
311: 	for _, dev := range egressDevs {
312: 		err = removeTCFilters(dev, directionToParent(dirEgress))
313: 		if err != nil {
314: 			log.WithError(err).Errorf("couldn't remove egress tc filters from %s", dev.Attrs().Name)
315: 		}
316: 	}
317: 
318: 	return nil
319: }
