321: // reloadHostDatapath (re)attaches programs from bpf_host.c to:
322: // - cilium_host: cil_to_host ingress and cil_from_host to egress
323: // - cilium_net: cil_to_host to ingress
324: // - native devices: cil_from_netdev to ingress and (optionally) cil_to_netdev to egress if certain features require it
325: func (l *loader) reloadHostDatapath(ep datapath.Endpoint, spec *ebpf.CollectionSpec, devices []string) error {
326: 	// Replace programs on cilium_host.
327: 	host, err := safenetlink.LinkByName(ep.InterfaceName())
328: 	if err != nil {
329: 		return fmt.Errorf("retrieving device %s: %w", ep.InterfaceName(), err)
330: 	}
331: 
332: 	coll, commit, err := loadDatapath(spec, ELFMapSubstitutions(ep), ELFVariableSubstitutions(ep))
333: 	if err != nil {
334: 		return err
335: 	}
336: 	defer coll.Close()
337: 
338: 	// Attach cil_to_host to cilium_host ingress.
339: 	if err := attachSKBProgram(host, coll.Programs[symbolToHostEp], symbolToHostEp,
340: 		bpffsDeviceLinksDir(bpf.CiliumPath(), host), netlink.HANDLE_MIN_INGRESS, option.Config.EnableTCX); err != nil {
341: 		return fmt.Errorf("interface %s ingress: %w", ep.InterfaceName(), err)
342: 	}
343: 	// Attach cil_from_host to cilium_host egress.
344: 	if err := attachSKBProgram(host, coll.Programs[symbolFromHostEp], symbolFromHostEp,
345: 		bpffsDeviceLinksDir(bpf.CiliumPath(), host), netlink.HANDLE_MIN_EGRESS, option.Config.EnableTCX); err != nil {
346: 		return fmt.Errorf("interface %s egress: %w", ep.InterfaceName(), err)
347: 	}
348: 
349: 	if err := commit(); err != nil {
350: 		return fmt.Errorf("committing bpf pins: %w", err)
